import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Pie, Line } from 'react-chartjs-2';
import 'chart.js/auto';
import './dashboard.css';
import Header from './Header';

const API_URL = 'http://localhost:9000';

const Dashboard = ({ token }) => {
    const [portfolio, setPortfolio] = useState([]);
    const [marketData, setMarketData] = useState([]);
    const [buySymbol, setBuySymbol] = useState('');
    const [buyQuantity, setBuyQuantity] = useState('');
    const [sellSymbol, setSellSymbol] = useState('');
    const [sellQuantity, setSellQuantity] = useState('');
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');
    const [username, setUsername] = useState('');

    useEffect(() => {
        if (!token) {
            setError("Utilisateur non connecté");
            return;
        }
        const decodedToken = JSON.parse(atob(token.split('.')[1]));
        setUsername(decodedToken.username);
        fetchPortfolio(decodedToken.username);
        fetchMarketData();
    }, [token]);

    const fetchPortfolio = async (user) => {
        try {
            const response = await axios.get(`${API_URL}/portfolio/${user}`);
            setPortfolio(response.data);
        } catch (error) {
            setError("Erreur lors du chargement du portefeuille.");
        }
    };

    const fetchMarketData = async () => {
        try {
            const response = await axios.get(`${API_URL}/market-data`);
            setMarketData(response.data);
        } catch (error) {
            setError("Erreur lors du chargement des données du marché.");
        }
    };

    const handleAddAsset = async (e) => {
        e.preventDefault();
        if (!buySymbol || !buyQuantity) {
            setError("Veuillez remplir tous les champs.");
            return;
        }
        try {
            await axios.post(`${API_URL}/portfolio/add`, { userId: username, symbol: buySymbol, quantity: parseInt(buyQuantity) });
            setMessage("Action ajoutée avec succès !");
            setBuySymbol('');
            setBuyQuantity('');
            fetchPortfolio(username);
        } catch (error) {
            setError("Erreur lors de l'ajout de l'action.");
        }
    };

    const handleRemoveAsset = async (e) => {
        e.preventDefault();
        if (!sellSymbol || !sellQuantity) {
            setError("Veuillez remplir tous les champs.");
            return;
        }
        try {
            await axios.post(`${API_URL}/portfolio/remove`, { userId: username, symbol: sellSymbol, quantity: parseInt(sellQuantity) });
            setMessage("Action vendue avec succès !");
            setSellSymbol('');
            setSellQuantity('');
            fetchPortfolio(username);
        } catch (error) {
            setError("Erreur lors de la vente de l'action.");
        }
    };

    const portfolioChartData = {
        labels: portfolio.map(asset => asset.symbol),
        datasets: [
            {
                data: portfolio.map(asset => asset.quantity),
                backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4CAF50', '#F44336'],
            }
        ]
    };

    const marketChartData = {
        labels: marketData.map(data => data.date),
        datasets: [
            {
                label: 'Performance du marché',
                data: marketData.map(data => data.price),
                borderColor: '#007bff',
                fill: false,
            }
        ]
    };

    return (
        <>
            <Header />
            <div className="dashboard">
                <h2>📊 Mon Portefeuille</h2>
                {error && <p className="error">{error}</p>}
                {message && <p className="message">{message}</p>}

                <div className="charts-container">
                    <div className="chart-box">
                        <h3>Répartition des actifs</h3>
                        <Pie data={portfolioChartData} />
                    </div>
                    <div className="chart-box">
                        <h3>Performance du portefeuille</h3>
                        <Line data={marketChartData} />
                    </div>
                </div>

                <div className="forms-container">
                    <div className="form-box">
                        <h3>➕ Acheter une action</h3>
                        <form onSubmit={handleAddAsset}>
                            <input type="text" placeholder="Symbole (ex: AAPL)" value={buySymbol} onChange={(e) => setBuySymbol(e.target.value)} required />
                            <input type="number" placeholder="Quantité" value={buyQuantity} onChange={(e) => setBuyQuantity(e.target.value)} required />
                            <button type="submit">Acheter</button>
                        </form>
                    </div>
                    <div className="form-box">
                        <h3>➖ Vendre une action</h3>
                        <form onSubmit={handleRemoveAsset}>
                            <input type="text" placeholder="Symbole (ex: AAPL)" value={sellSymbol} onChange={(e) => setSellSymbol(e.target.value)} required />
                            <input type="number" placeholder="Quantité" value={sellQuantity} onChange={(e) => setSellQuantity(e.target.value)} required />
                            <button type="submit">Vendre</button>
                        </form>
                    </div>
                </div>
            </div>
        </>
    );
};

export default Dashboard;
